package com.oyuki.exportrequest.controller; import com.oyuki.exportrequest.entity.ExportRequest; import com.oyuki.exportrequest.enums.ExportRequestStatus; import com.oyuki.exportrequest.repository.ExportRequestRepository; import com.oyuki.user.repository.UserRepository; import org.springframework.http.*; import org.springframework.security.core.Authentication; import org.springframework.web.bind.annotation.*; import java.util.*; @RestController @RequestMapping("/api/export-requests") public class ExportRequestController { private final ExportRequestRepository repo; private final UserRepository users; public ExportRequestController(ExportRequestRepository r,UserRepository u){repo=r;users=u;} @PostMapping public ResponseEntity<?> create(Authentication a,@RequestBody Map<String,String>b){ExportRequest e=ExportRequest.builder().customer(users.findById((Long)a.getPrincipal()).orElseThrow()).productName(b.get("productName")).destinationCountry(b.get("destinationCountry")).quantity(b.get("quantity")).notes(b.get("notes")).build();return ResponseEntity.status(201).body(map(repo.save(e)));} @GetMapping("/my") public List<Map<String,Object>> mine(Authentication a){return repo.findAllByCustomer_IdOrderByCreatedAtDesc((Long)a.getPrincipal()).stream().map(this::map).toList();} @GetMapping("/admin") public List<Map<String,Object>> all(){return repo.findAllByOrderByCreatedAtDesc().stream().map(this::map).toList();} @PatchMapping("/admin/{id}") public Map<String,Object> update(@PathVariable Long id,@RequestBody Map<String,String>b){ExportRequest e=repo.findById(id).orElseThrow();if(b.get("status")!=null)e.setStatus(ExportRequestStatus.valueOf(b.get("status")));e.setAdminNote(b.get("adminNote"));return map(repo.save(e));} private Map<String,Object> map(ExportRequest e){Map<String,Object>m=new LinkedHashMap<>();m.put("id",e.getId());m.put("customerName",e.getCustomer().getFullName());m.put("productName",e.getProductName());m.put("destinationCountry",e.getDestinationCountry());m.put("quantity",e.getQuantity());m.put("notes",e.getNotes());m.put("status",e.getStatus());m.put("adminNote",e.getAdminNote());m.put("createdAt",e.getCreatedAt());return m;} }